func solve(nums: Array<Int64>, queries: Array<Array<Int64>>): Array<Int64> {
    fun lowerBound(arr: Array<Int>, x: Int): Int {
        var low = 0
        var high = arr.size
        while (low < high) {
            val mid = (low + high) / 2
            if (arr[mid] < x) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        return low
    }

    fun upperBound(arr: Array<Int>, x: Int): Int {
        var low = 0
        var high = arr.size
        while (low < high) {
            val mid = (low + high) / 2
            if (arr[mid] <= x) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        return low
    }

    val n = nums.size
    val distinctMap = mutableMapOf<Int64, Int>()
    val distinctList = mutableListOf<Int64>()
    for (x in nums) {
        if (!distinctMap.containsKey(x)) {
            distinctMap[x] = distinctList.size
            distinctList.add(x)
        }
    }
    val distinctCount = distinctList.size

    val occ = Array(distinctCount) { mutableListOf<Int>() }
    for (i in 0 until n) {
        val x = nums[i]
        val id = distinctMap[x]!!
        occ[id].add(i)
    }

    val occArrays = Array(distinctCount) { idx ->
        occ[idx].toTypedArray()
    }

    val ans = mutableListOf<Int64>()
    for (q in queries) {
        val l = q[0].toInt()
        val r = q[1].toInt()
        val threshold = q[2].toInt()
        var candidateValue = -1L
        var candidateFreq = 0
        for (id in 0 until distinctCount) {
            val positions = occArrays[id]
            if (positions.isEmpty()) continue
            val leftIndex = lowerBound(positions, l)
            val rightIndex = upperBound(positions, r)
            val count = rightIndex - leftIndex
            if (count < threshold) continue

            val current = distinctList[id]
            if (candidateValue == -1L) {
                candidateValue = current
                candidateFreq = count
            } else {
                if (count > candidateFreq) {
                    candidateValue = current
                    candidateFreq = count
                } else if (count == candidateFreq && current < candidateValue) {
                    candidateValue = current
                }
            }
        }
        ans.add(if (candidateValue == -1L) -1 else candidateValue)
    }
    return ans.toTypedArray()
}
