```swift
func solve(nums: Array<Int64>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let n = nums.count
    let m = queries.count
    guard n > 0 && m > 0 else {
        return Array<Int64>()
    }

    let distinctSet = Set(nums)
    let distinct = distinctSet.sorted()
    let d = distinct.count
    var comp_map = [Int64: Int]()
    for (index, value) in distinct.enumerated() {
        comp_map[value] = index
    }
    var arr = [Int](repeating: 0, count: n)
    for i in 0..<n {
        arr[i] = comp_map[nums[i]]!
    }

    let block_size = Int(Double(n).squareRoot().rounded(.up))
    var q_list = [(l: Int, r: Int, threshold: Int64, idx: Int)]()
    for idx in 0..<m {
        let q = queries[idx]
        let l = Int(q[0])
        let r = Int(q[1])
        let threshold = q[2]
        q_list.append((l: l, r: r, threshold: threshold, idx: idx))
    }

    q_list.sort(by: {
        let block1 = $0.l / block_size
        let block2 = $1.l / block_size
        if block1 != block2 {
            return block1 < block2
        } else {
            return $0.r < $1.r
        }
    })

    var freq = [Int](repeating: 0, count: d)
    var freq_freq = [Int](repeating: 0, count: n+1)
    freq_freq[0] = d
    var max_freq = 0

    var left_ptr = 0
    var right_ptr = -1
    var ans_arr = [Int64](repeating: -1, count: m)

    for q in q_list {
        let l = q.l
        let r = q.r
        let threshold = q.threshold
        let idx = q.idx

        while right_ptr < r {
            right_ptr += 1
            let x = arr[right_ptr]
            let old_freq = freq[x]
            let new_freq = old_freq + 1
            freq[x] = new_freq
            freq_freq[old_freq] -= 1
            freq_freq[new_freq] += 1
            if new_freq > max_freq {
                max_freq = new_freq
            }
        }

        while right_ptr > r {
            let x = arr[right_ptr]
            let old_freq = freq[x]
            let new_freq = old_freq - 1
            freq[x] = new_freq
            freq_freq[old_freq] -= 1
            freq_freq[new_freq] += 1
            if old_freq == max_freq && freq_freq[old_freq] == 0 {
                max_freq = old_freq - 1
            }
            right_ptr -= 1
        }

        while left_ptr < l {
            let x = arr[left_ptr]
            let old_freq = freq[x]
            let new_freq = old_freq - 1
            freq[x] = new_freq
            freq_freq[old_freq] -= 1
            freq_freq[new_freq] += 1
            if old_freq == max_freq && freq_freq[old_freq] == 0 {
                max_freq = old_freq - 1
            }
            left_ptr += 1
        }

        while left_ptr > l {
            left_ptr -= 1
            let x = arr[left_ptr]
            let old_freq = freq[x]
            let new_freq = old_freq + 1
            freq[x] = new_freq
            freq_freq[old_freq] -= 1
            freq_freq[new_freq] += 1
            if new_freq > max_freq {
                max_freq = new_freq
            }
        }

        if max_freq < threshold {
            ans_arr[idx] = -1
        } else {
            var candidate_val = Int64.max
            for x in 0..<d {
                if freq[x] == max_freq {
                    let num_val = distinct[x]
                    if num_val < candidate_val {
                        candidate_val = num_val
                    }
                }
            }
            ans_arr[idx] = candidate_val
        }
    }

    return ans_arr
}
```

